const items = [];

for (const item of $input.all()) {
  const emails = (item.json.observer_emails || '').split(',');
  const firstNames = (item.json.observer_first_names || '').split(',');
  const lastNames = (item.json.observer_last_names || '').split(',');

  for (let i = 0; i < emails.length; i++) {
    if (!emails[i]) continue;

    items.push({
      json: {
        ...item.json,
        observer_email: emails[i].trim(),
        observer_first_name: firstNames[i]?.trim(),
        observer_last_name: lastNames[i]?.trim()
      }
    });
  }
}

return items;

const grouped = {};

for (const item of $input.all()) {
  const t = item.json;

  const email = t.project_manager_email;
  if (!email) continue;

  if (!grouped[email]) {
    grouped[email] = {
      pm_email: email,
      pm_name: `${t.project_manager_firstname || ''} ${t.project_manager_lastname || ''}`.trim(),
      tasks: []
    };
  }

  grouped[email].tasks.push({
    task_id: t.task_id,
    task_title: t.task_title,
    task_created_at: t.task_created_at,
    task_due_date: t.task_due_date,
    task_status: t.task_status,
    overdue_days: t.overdue_days,
    project_title: t.project_title,
    milestone_title: t.milestone_title,
    task_owner_name: `${t.task_owner_firstname || ''} ${t.task_owner_lastname || ''}`.trim()
  });
}

return Object.values(grouped).map(u => ({
  json: {
    ...u,
    total_overdue_tasks: u.tasks.length
  }
}));

